import { createSlice } from '@reduxjs/toolkit'
import axios from 'axios'


export const userDetailsSlice = createSlice({
    name: 'userDetails',
    initialState: { user: {}},
    reducers: {
        userDetailsRequest: (state, action) => {
            state.loading = true;
        },

        userDetailsSucces: (state, action) => { 
            state.loading = false;
            state.user = action.payload; 
        },

        userDetailsFail: (state, action) => { 
           state.loading = false; 
            state.error = action.payload;
        }
    }
})
export const { userDetailsRequest, userDetailsSucces, userDetailsFail, userLogout } = userDetailsSlice.actions
export default userDetailsSlice.reducer;


// thunk functions to login a user

export const register = (first_name, last_name, email, password) => async (dispatch) => {
    try{
        dispatch(userRegisterRequest())

        const headers = {
            'Content-Type': 'application/json'
        }
        const params = {
            email: email,
            password: password,
            ...(first_name ? { 'first_name': first_name } : {}),
            ...(last_name ? { 'last_name': last_name } : {})
        }

        const { data } = await axios.post(
            'api/users/register/',
            params,
            { headers: headers }
            )

        console.log(data)

        dispatch(userRegisterSucces(data))

        localStorage.setItem('userInfo', JSON.stringify(data))

        // after the user register, log the user in
        dispatch(userLoginSucces(data))

    } catch (error) {
        const msg = (error.response && error.response.data.message ? error.response.data.message : error.message)
        dispatch(userRegisterFail(msg))
    }
}

export const logout = () => (dispatch) => {
    localStorage.removeItem('userInfo')
    dispatch(userLogout())
}
